import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Category {
  type: string;
  unread: number;
}

interface NotificationData {
  unreadCount: number;
  categories: Category[];
}

export default function Widget() {
  const { unreadCount, categories } = response.data as NotificationData;
  const theme = response.meta.theme;
  const primaryColor = response.meta.primaryColor;
  const accentColor = response.meta.accentColor;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: theme === 'dark' ? '#2C2C2C' : '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: primaryColor, mb: 1 }}>
              Notification Center
            </Typography>
            <Typography variant="body2" color="text.secondary">
              You have {unreadCount} unread notifications
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {categories.map((category, index) => (
              <Chip
                key={index}
                label={`${category.type}: ${category.unread}`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: accentColor, color: '#FFFFFF' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
